<template>
  <span>{{ this.default }}</span>
</template>

<script>
export default {
  name: "UseAnimatedNumbers",
  props: {
    number: Number,
    duration: Number,
  },
  data() {
    return {
      default: 0,
    };
  },
  mounted() {
    let timer = setInterval(() => {
      this.default += 1;
      if (this.default == this.number) clearInterval(timer);
    }, Math.abs(Math.floor(this.duration / this.number)));
  },
};
</script>

