
<template>
  <useHeader @changeTabAction="changeTab" v-if="isAllowed"></useHeader>
  <div v-else></div>
  <section>
    <KeepAlive>
      <component :is="currentTab" :isAuthed="isAuthed" :isAllowed="isAllowed"></component>
    </KeepAlive>
  </section>
  <link rel="preconnect" href="https://fonts.googleapis.com" />
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
  <link
    href="https://fonts.googleapis.com/css2?family=Source+Sans+Pro:wght@400;600;700;900&display=swap"
    rel="stylesheet"
  />
  <p class="copy">Project by RedRose</p>
</template>

<script>
import useHeader from "./components/useHeader.vue";
import useNewsPage from "./components/useNewsPage.vue";
import useDownloadPage from "./components/useDownloadPage.vue";
import useAboutPage from "./components/useAboutPage.vue";
import useAuthorPage from "./components/useAuthorPage.vue";
import supabase from "@/api/supabase";

export default {
  name: "App",
  components: {
    useHeader,
    useNewsPage,
    useDownloadPage,
    useAboutPage,
    useAuthorPage,
  },
  data() {
    return {
      currentTab: "useNewsPage",
      isAuthed: true,
      isAllowed: true,
    };
  },
  methods: {
    changeTab(page) {
      this.currentTab = `use${page}Page`;
    },
    async Checker() {
      const { data } = await supabase.auth.getSession();
      this.isAuthed = data.session != null ? true : false;

      if (data.session == null) return;

      const { data: data2 } = await supabase
        .from("permissions")
        .select("isallowed")
        .eq("id", data.session.user.id);

      this.isAllowed = data2[0].isallowed;
    },
  },
  mounted() {
    // this.Checker();
  },
};
</script>

